using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: discriminator property renamed from "Discriminator" to "$type".
        // Preserve old name so existing documents are still queryable.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Breaking change: id no longer includes the discriminator prefix.
        // Preserve "Blog|<key>" format so existing documents are found.
        modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

        // Breaking change: key property is now mapped directly to JSON "id".
        // Restore the EF8 shadow-property behaviour so the key is still
        // stored as a separate "Id" property in the document.
        modelBuilder.Entity<Blog>().HasShadowId();

        // Breaking change: HasIndex now throws for Cosmos (was silently ignored).
        // Removed – Cosmos indexes all properties by default.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

